static symmetryCyclicGroupPinwheelSvg = `<?xml version="1.0" standalone="no"?>
<!DOCTYPE svg PUBLIC "-//W3C//DTD SVG 20010904//EN"
 "http://www.w3.org/TR/2001/REC-SVG-20010904/DTD/svg10.dtd">
<svg version="1.0" xmlns="http://www.w3.org/2000/svg"
 width="700" height="700" viewBox="0 0 700 700"
 preserveAspectRatio="xMidYMid meet">
<metadata>Symmetry Cyclic Group Pinwheel</metadata>
<g fill="none" stroke="#000000">

<!-- Title -->
<text x="350" y="35" font-family="Arial" font-size="20" fill="#000000" text-anchor="middle" font-weight="bold">Cyclic Group C₅ — Pinwheel</text>
<text x="350" y="58" font-family="Arial" font-size="12" fill="#555555" text-anchor="middle">Rotational symmetry of order 5 but NO reflective symmetry</text>

<!-- 5-blade pinwheel centred at (350,350) -->
<!-- Each blade: a curved arm shape, rotated 72° apart -->
<!-- Using paths to create asymmetric blades that show chirality -->

<!-- Blade 1 (0°) -->
<path d="M 350 350 L 350 200 Q 390 195 410 230 Q 380 260 350 350" fill="#CCCCCC" stroke="#000000" stroke-width="2"/>
<!-- Blade 2 (72°) -->
<path d="M 350 350 L 494 259 Q 510 296 492 325 Q 462 314 350 350" fill="#CCCCCC" stroke="#000000" stroke-width="2" transform="rotate(72,350,350)"/>
<!-- Blade 3 (144°) -->
<path d="M 350 350 L 350 200 Q 390 195 410 230 Q 380 260 350 350" fill="#CCCCCC" stroke="#000000" stroke-width="2" transform="rotate(144,350,350)"/>
<!-- Blade 4 (216°) -->
<path d="M 350 350 L 350 200 Q 390 195 410 230 Q 380 260 350 350" fill="#CCCCCC" stroke="#000000" stroke-width="2" transform="rotate(216,350,350)"/>
<!-- Blade 5 (288°) -->
<path d="M 350 350 L 350 200 Q 390 195 410 230 Q 380 260 350 350" fill="#CCCCCC" stroke="#000000" stroke-width="2" transform="rotate(288,350,350)"/>

<!-- Centre hub -->
<circle cx="350" cy="350" r="20" fill="#EEEEEE" stroke="#000000" stroke-width="2.5"/>

<!-- Rotation arcs showing 72° between blades -->
<circle cx="350" cy="350" r="175" fill="none" stroke="#CCCCCC" stroke-width="1" stroke-dasharray="3,3"/>
<!-- 72° arc -->
<path d="M 350 175 A 175 175 0 0 1 516 296" stroke="#000000" stroke-width="2" fill="none" marker-end="url(#arrCG)"/>
<text x="462" y="205" font-family="Arial" font-size="14" fill="#000000" font-weight="bold">72°</text>

<!-- X mark showing NO reflection symmetry -->
<text x="350" y="560" font-family="Arial" font-size="14" fill="#000000" text-anchor="middle" font-weight="bold">No Lines of Symmetry</text>
<!-- Attempt to draw a "reflection line" that clearly does NOT work -->
<line x1="350" y1="175" x2="350" y2="535" stroke="#000000" stroke-width="1.5" stroke-dasharray="6,4"/>
<text x="360" y="525" font-family="Arial" font-size="12" fill="#000000">✗ not a</text>
<text x="360" y="540" font-family="Arial" font-size="12" fill="#000000">symmetry line</text>

<!-- Comparison note -->
<rect x="30" y="580" width="640" height="100" fill="#F5F5F5" stroke="#AAAAAA" stroke-width="1" rx="4"/>
<text x="350" y="602" font-family="Arial" font-size="13" fill="#000000" text-anchor="middle" font-weight="bold">C₅ vs D₅ Comparison</text>
<text x="350" y="622" font-family="Arial" font-size="12" fill="#000000" text-anchor="middle">C₅ (pinwheel):  5 rotations only,  |C₅| = 5,  NO reflections</text>
<text x="350" y="640" font-family="Arial" font-size="12" fill="#000000" text-anchor="middle">D₅ (reg. pentagon):  5 rotations + 5 reflections,  |D₅| = 10</text>
<text x="350" y="658" font-family="Arial" font-size="11" fill="#555555" text-anchor="middle">C₅ = ⟨r | r⁵ = e⟩   ·   Elements: {e, r, r², r³, r⁴}   ·   Angle: 360°/5 = 72°</text>
<text x="350" y="674" font-family="Arial" font-size="11" fill="#555555" text-anchor="middle">Chirality: pinwheel and its mirror image are not equivalent</text>

<defs>
  <marker id="arrCG" markerWidth="10" markerHeight="10" refX="9" refY="3" orient="auto">
    <polygon points="0 0,10 3,0 6" fill="#000000"/>
  </marker>
</defs>
</g>
</svg>`;

